    struct UnionFind {
        parent: Vec<i64>,
        rank: Vec<i64>,
        online: Vec<bool>,
    }

    impl UnionFind {
        fn new(size: i64) -> Self {
            let parent = (0..=size).map(|i| i).collect::<Vec<_>>();
            let rank = vec![0; (size + 1) as usize];
            let online = vec![true; (size + 1) as usize];
            UnionFind { parent, rank, online }
        }

        fn find(&mut self, x: i64) -> i64 {
            if self.parent[x as usize] != x {
                self.parent[x as usize] = self.find(self.parent[x as usize]);
            }
            self.parent[x as usize]
        }

        fn union(&mut self, x: i64, y: i64) {
            let x_root = self.find(x);
            let y_root = self.find(y);

            if x_root == y_root {
                return;
            }

            if self.rank[x_root as usize] < self.rank[y_root as usize] {
                self.parent[x_root as usize] = y_root;
            } else {
                self.parent[y_root as usize] = x_root;
                if self.rank[x_root as usize] == self.rank[y_root as usize] {
                    self.rank[x_root as usize] += 1;
                }
            }
        }

        fn mark_offline(&mut self, x: i64) {
            self.online[x as usize] = false;
        }

        fn is_online(&self, x: i64) -> bool {
            self.online[x as usize]
        }
